var VERSES_ZECHARIAH=[{"ref":"Zechariah 1:1","short":"Zech 1:1","text":"In the eighth month of the second year of Darius, the word of the Lord came to the prophet Zechariah son of Berekiah, the son of Iddo:","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":1},{"ref":"Zechariah 1:2","short":"Zech 1:2","text":"“The Lord was very angry with your ancestors.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":2},{"ref":"Zechariah 1:3","short":"Zech 1:3","text":"Therefore tell the people: This is what the Lord Almighty says: ‘Return to me,’ declares the Lord Almighty, ‘and I will return to you,’ says the Lord Almighty.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":3},{"ref":"Zechariah 1:4","short":"Zech 1:4","text":"Do not be like your ancestors, to whom the earlier prophets proclaimed: This is what the Lord Almighty says: ‘Turn from your evil ways and your evil practices.’ But they would not listen or pay attention to me, declares the Lord.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":4},{"ref":"Zechariah 1:5","short":"Zech 1:5","text":"Where are your ancestors now? And the prophets, do they live forever?","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":5},{"ref":"Zechariah 1:6","short":"Zech 1:6","text":"But did not my words and my decrees, which I commanded my servants the prophets, overtake your ancestors? “Then they repented and said, ‘The Lord Almighty has done to us what our ways and practices deserve, just as he determined to do.’ ”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":6},{"ref":"Zechariah 1:7","short":"Zech 1:7","text":"On the twenty-fourth day of the eleventh month, the month of Shebat, in the second year of Darius, the word of the Lord came to the prophet Zechariah son of Berekiah, the son of Iddo.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":7},{"ref":"Zechariah 1:8","short":"Zech 1:8","text":"During the night I had a vision, and there before me was a man mounted on a red horse. He was standing among the myrtle trees in a ravine. Behind him were red, brown and white horses.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":8},{"ref":"Zechariah 1:9","short":"Zech 1:9","text":"I asked, “What are these, my lord?” The angel who was talking with me answered, “I will show you what they are.”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":9},{"ref":"Zechariah 1:10","short":"Zech 1:10","text":"Then the man standing among the myrtle trees explained, “They are the ones the Lord has sent to go throughout the earth.”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":10},{"ref":"Zechariah 1:11","short":"Zech 1:11","text":"And they reported to the angel of the Lord who was standing among the myrtle trees, “We have gone throughout the earth and found the whole world at rest and in peace.”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":11},{"ref":"Zechariah 1:12","short":"Zech 1:12","text":"Then the angel of the Lord said, “Lord Almighty, how long will you withhold mercy from Jerusalem and from the towns of Judah, which you have been angry with these seventy years?”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":12},{"ref":"Zechariah 1:13","short":"Zech 1:13","text":"So the Lord spoke kind and comforting words to the angel who talked with me.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":13},{"ref":"Zechariah 1:14","short":"Zech 1:14","text":"Then the angel who was speaking to me said, “Proclaim this word: This is what the Lord Almighty says: ‘I am very jealous for Jerusalem and Zion,","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":14},{"ref":"Zechariah 1:15","short":"Zech 1:15","text":"and I am very angry with the nations that feel secure. I was only a little angry, but they went too far with the punishment.’","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":15},{"ref":"Zechariah 1:16","short":"Zech 1:16","text":"“Therefore this is what the Lord says: ‘I will return to Jerusalem with mercy, and there my house will be rebuilt. And the measuring line will be stretched out over Jerusalem,’ declares the Lord Almighty.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":16},{"ref":"Zechariah 1:17","short":"Zech 1:17","text":"“Proclaim further: This is what the Lord Almighty says: ‘My towns will again overflow with prosperity, and the Lord will again comfort Zion and choose Jerusalem.’ ”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":17},{"ref":"Zechariah 1:18","short":"Zech 1:18","text":"Then I looked up, and there before me were four horns.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":18},{"ref":"Zechariah 1:19","short":"Zech 1:19","text":"I asked the angel who was speaking to me, “What are these?” He answered me, “These are the horns that scattered Judah, Israel and Jerusalem.”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":19},{"ref":"Zechariah 1:20","short":"Zech 1:20","text":"Then the Lord showed me four craftsmen.","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":20},{"ref":"Zechariah 1:21","short":"Zech 1:21","text":"I asked, “What are these coming to do?” He answered, “These are the horns that scattered Judah so that no one could raise their head, but the craftsmen have come to terrify them and throw down these horns of the nations who lifted up their horns against the land of Judah to scatter its people.”","url":"ot/zechariah/Zechariah_1.html","book":"Zechariah","ch":1,"v":21},{"ref":"Zechariah 2:1","short":"Zech 2:1","text":"Then I looked up, and there before me was a man with a measuring line in his hand.","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":1},{"ref":"Zechariah 2:2","short":"Zech 2:2","text":"I asked, “Where are you going?” He answered me, “To measure Jerusalem, to find out how wide and how long it is.”","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":2},{"ref":"Zechariah 2:3","short":"Zech 2:3","text":"While the angel who was speaking to me was leaving, another angel came to meet him","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":3},{"ref":"Zechariah 2:4","short":"Zech 2:4","text":"and said to him: “Run, tell that young man, ‘Jerusalem will be a city without walls because of the great number of people and animals in it.","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":4},{"ref":"Zechariah 2:5","short":"Zech 2:5","text":"And I myself will be a wall of fire around it,’ declares the Lord, ‘and I will be its glory within.’","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":5},{"ref":"Zechariah 2:6","short":"Zech 2:6","text":"“Come! Come! Flee from the land of the north,” declares the Lord, “for I have scattered you to the four winds of heaven,” declares the Lord.","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":6},{"ref":"Zechariah 2:7","short":"Zech 2:7","text":"“Come, Zion! Escape, you who live in Daughter Babylon!”","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":7},{"ref":"Zechariah 2:8","short":"Zech 2:8","text":"For this is what the Lord Almighty says: “After the Glorious One has sent me against the nations that have plundered you—for whoever touches you touches the apple of his eye—","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":8},{"ref":"Zechariah 2:9","short":"Zech 2:9","text":"I will surely raise my hand against them so that their slaves will plunder them. Then you will know that the Lord Almighty has sent me.","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":9},{"ref":"Zechariah 2:10","short":"Zech 2:10","text":"“Shout and be glad, Daughter Zion. For I am coming, and I will live among you,” declares the Lord.","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":10},{"ref":"Zechariah 2:11","short":"Zech 2:11","text":"“Many nations will be joined with the Lord in that day and will become my people. I will live among you and you will know that the Lord Almighty has sent me to you.","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":11},{"ref":"Zechariah 2:12","short":"Zech 2:12","text":"The Lord will inherit Judah as his portion in the holy land and will again choose Jerusalem.","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":12},{"ref":"Zechariah 2:13","short":"Zech 2:13","text":"Be still before the Lord, all mankind, because he has roused himself from his holy dwelling.”","url":"ot/zechariah/Zechariah_2.html","book":"Zechariah","ch":2,"v":13},{"ref":"Zechariah 3:1","short":"Zech 3:1","text":"Then he showed me Joshua the high priest standing before the angel of the Lord, and Satan standing at his right side to accuse him.","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":1},{"ref":"Zechariah 3:2","short":"Zech 3:2","text":"The Lord said to Satan, “The Lord rebuke you, Satan! The Lord, who has chosen Jerusalem, rebuke you! Is not this man a burning stick snatched from the fire?”","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":2},{"ref":"Zechariah 3:3","short":"Zech 3:3","text":"Now Joshua was dressed in filthy clothes as he stood before the angel.","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":3},{"ref":"Zechariah 3:4","short":"Zech 3:4","text":"The angel said to those who were standing before him, “Take off his filthy clothes.” Then he said to Joshua, “See, I have taken away your sin, and I will put fine garments on you.”","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":4},{"ref":"Zechariah 3:5","short":"Zech 3:5","text":"Then I said, “Put a clean turban on his head.” So they put a clean turban on his head and clothed him, while the angel of the Lord stood by.","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":5},{"ref":"Zechariah 3:6","short":"Zech 3:6","text":"The angel of the Lord gave this charge to Joshua:","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":6},{"ref":"Zechariah 3:7","short":"Zech 3:7","text":"“This is what the Lord Almighty says: ‘If you will walk in obedience to me and keep my requirements, then you will govern my house and have charge of my courts, and I will give you a place among these standing here.","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":7},{"ref":"Zechariah 3:8","short":"Zech 3:8","text":"“ ‘Listen, High Priest Joshua, you and your associates seated before you, who are men symbolic of things to come: I am going to bring my servant, the Branch.","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":8},{"ref":"Zechariah 3:9","short":"Zech 3:9","text":"See, the stone I have set in front of Joshua! There are seven eyes on that one stone, and I will engrave an inscription on it,’ says the Lord Almighty, ‘and I will remove the sin of this land in a single day.","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":9},{"ref":"Zechariah 3:10","short":"Zech 3:10","text":"“ ‘In that day each of you will invite your neighbor to sit under your vine and fig tree,’ declares the Lord Almighty.”","url":"ot/zechariah/Zechariah_3.html","book":"Zechariah","ch":3,"v":10},{"ref":"Zechariah 4:1","short":"Zech 4:1","text":"Then the angel who talked with me returned and woke me up, like someone awakened from sleep.","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":1},{"ref":"Zechariah 4:2","short":"Zech 4:2","text":"He asked me, “What do you see?” I answered, “I see a solid gold lampstand with a bowl at the top and seven lamps on it, with seven channels to the lamps.","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":2},{"ref":"Zechariah 4:3","short":"Zech 4:3","text":"Also there are two olive trees by it, one on the right of the bowl and the other on its left.”","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":3},{"ref":"Zechariah 4:4","short":"Zech 4:4","text":"I asked the angel who talked with me, “What are these, my lord?”","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":4},{"ref":"Zechariah 4:5","short":"Zech 4:5","text":"He answered, “Do you not know what these are?” “No, my lord,” I replied.","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":5},{"ref":"Zechariah 4:6","short":"Zech 4:6","text":"So he said to me, “This is the word of the Lord to Zerubbabel: ‘Not by might nor by power, but by my Spirit,’ says the Lord Almighty.","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":6},{"ref":"Zechariah 4:7","short":"Zech 4:7","text":"“What are you, mighty mountain? Before Zerubbabel you will become level ground. Then he will bring out the capstone to shouts of ‘God bless it! God bless it!’ ”","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":7},{"ref":"Zechariah 4:8","short":"Zech 4:8","text":"Then the word of the Lord came to me:","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":8},{"ref":"Zechariah 4:9","short":"Zech 4:9","text":"“The hands of Zerubbabel have laid the foundation of this temple; his hands will also complete it. Then you will know that the Lord Almighty has sent me to you.","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":9},{"ref":"Zechariah 4:10","short":"Zech 4:10","text":"“Who dares despise the day of small things, since the seven eyes of the Lord that range throughout the earth will rejoice when they see the chosen capstone in the hand of Zerubbabel?”","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":10},{"ref":"Zechariah 4:11","short":"Zech 4:11","text":"Then I asked the angel, “What are these two olive trees on the right and the left of the lampstand?”","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":11},{"ref":"Zechariah 4:12","short":"Zech 4:12","text":"Again I asked him, “What are these two olive branches beside the two gold pipes that pour out golden oil?”","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":12},{"ref":"Zechariah 4:13","short":"Zech 4:13","text":"He replied, “Do you not know what these are?” “No, my lord,” I said.","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":13},{"ref":"Zechariah 4:14","short":"Zech 4:14","text":"So he said, “These are the two who are anointed to serve the Lord of all the earth.”","url":"ot/zechariah/Zechariah_4.html","book":"Zechariah","ch":4,"v":14},{"ref":"Zechariah 5:1","short":"Zech 5:1","text":"I looked again, and there before me was a flying scroll.","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":1},{"ref":"Zechariah 5:2","short":"Zech 5:2","text":"He asked me, “What do you see?” I answered, “I see a flying scroll, twenty cubits long and ten cubits wide.”","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":2},{"ref":"Zechariah 5:3","short":"Zech 5:3","text":"And he said to me, “This is the curse that is going out over the whole land; for according to what it says on one side, every thief will be banished, and according to what it says on the other, everyone who swears falsely will be banished.","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":3},{"ref":"Zechariah 5:4","short":"Zech 5:4","text":"The Lord Almighty declares, ‘I will send it out, and it will enter the house of the thief and the house of anyone who swears falsely by my name. It will remain in that house and destroy it completely, both its timbers and its stones.’ ”","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":4},{"ref":"Zechariah 5:5","short":"Zech 5:5","text":"Then the angel who was speaking to me came forward and said to me, “Look up and see what is appearing.”","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":5},{"ref":"Zechariah 5:6","short":"Zech 5:6","text":"I asked, “What is it?” He replied, “It is a basket.” And he added, “This is the iniquity of the people throughout the land.”","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":6},{"ref":"Zechariah 5:7","short":"Zech 5:7","text":"Then the cover of lead was raised, and there in the basket sat a woman!","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":7},{"ref":"Zechariah 5:8","short":"Zech 5:8","text":"He said, “This is wickedness,” and he pushed her back into the basket and pushed its lead cover down on it.","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":8},{"ref":"Zechariah 5:9","short":"Zech 5:9","text":"Then I looked up—and there before me were two women, with the wind in their wings! They had wings like those of a stork, and they lifted up the basket between heaven and earth.","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":9},{"ref":"Zechariah 5:10","short":"Zech 5:10","text":"“Where are they taking the basket?” I asked the angel who was speaking to me.","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":10},{"ref":"Zechariah 5:11","short":"Zech 5:11","text":"He replied, “To the country of Babylonia to build a house for it. When the house is ready, the basket will be set there in its place.”","url":"ot/zechariah/Zechariah_5.html","book":"Zechariah","ch":5,"v":11},{"ref":"Zechariah 6:1","short":"Zech 6:1","text":"I looked up again, and there before me were four chariots coming out from between two mountains—mountains of bronze.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":1},{"ref":"Zechariah 6:2","short":"Zech 6:2","text":"The first chariot had red horses, the second black,","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":2},{"ref":"Zechariah 6:3","short":"Zech 6:3","text":"the third white, and the fourth dappled—all of them powerful.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":3},{"ref":"Zechariah 6:4","short":"Zech 6:4","text":"I asked the angel who was speaking to me, “What are these, my lord?”","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":4},{"ref":"Zechariah 6:5","short":"Zech 6:5","text":"The angel answered me, “These are the four spirits of heaven, going out from standing in the presence of the Lord of the whole world.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":5},{"ref":"Zechariah 6:6","short":"Zech 6:6","text":"The one with the black horses is going toward the north country, the one with the white horses toward the west, and the one with the dappled horses toward the south.”","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":6},{"ref":"Zechariah 6:7","short":"Zech 6:7","text":"When the powerful horses went out, they were straining to go throughout the earth. And he said, “Go throughout the earth!” So they went throughout the earth.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":7},{"ref":"Zechariah 6:8","short":"Zech 6:8","text":"Then he called to me, “Look, those going toward the north country have given my Spirit rest in the land of the north.”","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":8},{"ref":"Zechariah 6:9","short":"Zech 6:9","text":"The word of the Lord came to me:","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":9},{"ref":"Zechariah 6:10","short":"Zech 6:10","text":"“Take silver and gold from the exiles Heldai, Tobijah and Jedaiah, who have arrived from Babylon. Go the same day to the house of Josiah son of Zephaniah.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":10},{"ref":"Zechariah 6:11","short":"Zech 6:11","text":"Take the silver and gold and make a crown, and set it on the head of the high priest, Joshua son of Jozadak.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":11},{"ref":"Zechariah 6:12","short":"Zech 6:12","text":"Tell him this is what the Lord Almighty says: ‘Here is the man whose name is the Branch, and he will branch out from his place and build the temple of the Lord.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":12},{"ref":"Zechariah 6:13","short":"Zech 6:13","text":"It is he who will build the temple of the Lord, and he will be clothed with majesty and will sit and rule on his throne. And he will be a priest on his throne. And there will be harmony between the two.’","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":13},{"ref":"Zechariah 6:14","short":"Zech 6:14","text":"The crown will be given to Heldai, Tobijah, Jedaiah and Hen son of Zephaniah as a memorial in the temple of the Lord.","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":14},{"ref":"Zechariah 6:15","short":"Zech 6:15","text":"Those who are far away will come and help to build the temple of the Lord, and you will know that the Lord Almighty has sent me to you. This will happen if you diligently obey the Lord your God.”","url":"ot/zechariah/Zechariah_6.html","book":"Zechariah","ch":6,"v":15},{"ref":"Zechariah 7:1","short":"Zech 7:1","text":"In the fourth year of King Darius, the word of the Lord came to Zechariah on the fourth day of the ninth month, the month of Kislev.","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":1},{"ref":"Zechariah 7:2","short":"Zech 7:2","text":"The people of Bethel had sent Sharezer and Regem-Melek, together with their men, to entreat the Lord","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":2},{"ref":"Zechariah 7:3","short":"Zech 7:3","text":"by asking the priests of the house of the Lord Almighty and the prophets, “Should I mourn and fast in the fifth month, as I have done for so many years?”","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":3},{"ref":"Zechariah 7:4","short":"Zech 7:4","text":"Then the word of the Lord Almighty came to me:","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":4},{"ref":"Zechariah 7:5","short":"Zech 7:5","text":"“Ask all the people of the land and the priests, ‘When you fasted and mourned in the fifth and seventh months for the past seventy years, was it really for me that you fasted?","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":5},{"ref":"Zechariah 7:6","short":"Zech 7:6","text":"And when you were eating and drinking, were you not just feasting for yourselves?","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":6},{"ref":"Zechariah 7:7","short":"Zech 7:7","text":"Are these not the words the Lord proclaimed through the earlier prophets when Jerusalem and its surrounding towns were at rest and prosperous, and the Negev and the western foothills were settled?’ ”","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":7},{"ref":"Zechariah 7:8","short":"Zech 7:8","text":"And the word of the Lord came again to Zechariah:","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":8},{"ref":"Zechariah 7:9","short":"Zech 7:9","text":"“This is what the Lord Almighty said: ‘Administer true justice; show mercy and compassion to one another.","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":9},{"ref":"Zechariah 7:10","short":"Zech 7:10","text":"Do not oppress the widow or the fatherless, the foreigner or the poor. Do not plot evil against each other.’","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":10},{"ref":"Zechariah 7:11","short":"Zech 7:11","text":"“But they refused to pay attention; stubbornly they turned their backs and covered their ears.","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":11},{"ref":"Zechariah 7:12","short":"Zech 7:12","text":"They made their hearts as hard as flint and would not listen to the law or to the words that the Lord Almighty had sent by his Spirit through the earlier prophets. So the Lord Almighty was very angry.","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":12},{"ref":"Zechariah 7:13","short":"Zech 7:13","text":"“ ‘When I called, they did not listen; so when they called, I would not listen,’ says the Lord Almighty.","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":13},{"ref":"Zechariah 7:14","short":"Zech 7:14","text":"‘I scattered them with a whirlwind among all the nations, where they were strangers. The land they left behind them was so desolate that no one traveled through it. This is how they made the pleasant land desolate.’ ”","url":"ot/zechariah/Zechariah_7.html","book":"Zechariah","ch":7,"v":14},{"ref":"Zechariah 8:1","short":"Zech 8:1","text":"The word of the Lord Almighty came to me.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":1},{"ref":"Zechariah 8:2","short":"Zech 8:2","text":"This is what the Lord Almighty says: “I am very jealous for Zion; I am burning with jealousy for her.”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":2},{"ref":"Zechariah 8:3","short":"Zech 8:3","text":"This is what the Lord says: “I will return to Zion and dwell in Jerusalem. Then Jerusalem will be called the Faithful City, and the mountain of the Lord Almighty will be called the Holy Mountain.”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":3},{"ref":"Zechariah 8:4","short":"Zech 8:4","text":"This is what the Lord Almighty says: “Once again men and women of ripe old age will sit in the streets of Jerusalem, each of them with cane in hand because of their age.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":4},{"ref":"Zechariah 8:5","short":"Zech 8:5","text":"The city streets will be filled with boys and girls playing there.”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":5},{"ref":"Zechariah 8:6","short":"Zech 8:6","text":"This is what the Lord Almighty says: “It may seem marvelous to the remnant of this people at that time, but will it seem marvelous to me?” declares the Lord Almighty.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":6},{"ref":"Zechariah 8:7","short":"Zech 8:7","text":"This is what the Lord Almighty says: “I will save my people from the countries of the east and the west.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":7},{"ref":"Zechariah 8:8","short":"Zech 8:8","text":"I will bring them back to live in Jerusalem; they will be my people, and I will be faithful and righteous to them as their God.”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":8},{"ref":"Zechariah 8:9","short":"Zech 8:9","text":"This is what the Lord Almighty says: “Now hear these words, ‘Let your hands be strong so that the temple may be built.’ This is also what the prophets said who were present when the foundation was laid for the house of the Lord Almighty.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":9},{"ref":"Zechariah 8:10","short":"Zech 8:10","text":"Before that time there were no wages for people or hire for animals. No one could go about their business safely because of their enemies, since I had turned everyone against their neighbor.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":10},{"ref":"Zechariah 8:11","short":"Zech 8:11","text":"But now I will not deal with the remnant of this people as I did in the past,” declares the Lord Almighty.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":11},{"ref":"Zechariah 8:12","short":"Zech 8:12","text":"“The seed will grow well, the vine will yield its fruit, the ground will produce its crops, and the heavens will drop their dew. I will give all these things as an inheritance to the remnant of this people.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":12},{"ref":"Zechariah 8:13","short":"Zech 8:13","text":"Just as you, Judah and Israel, have been a curse among the nations, so I will save you, and you will be a blessing. Do not be afraid, but let your hands be strong.”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":13},{"ref":"Zechariah 8:14","short":"Zech 8:14","text":"This is what the Lord Almighty says: “Just as I had determined to bring disaster on you and showed no pity when your ancestors angered me,” says the Lord Almighty,","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":14},{"ref":"Zechariah 8:15","short":"Zech 8:15","text":"“so now I have determined to do good again to Jerusalem and Judah. Do not be afraid.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":15},{"ref":"Zechariah 8:16","short":"Zech 8:16","text":"These are the things you are to do: Speak the truth to each other, and render true and sound judgment in your courts;","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":16},{"ref":"Zechariah 8:17","short":"Zech 8:17","text":"do not plot evil against each other, and do not love to swear falsely. I hate all this,” declares the Lord.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":17},{"ref":"Zechariah 8:18","short":"Zech 8:18","text":"The word of the Lord Almighty came to me.","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":18},{"ref":"Zechariah 8:19","short":"Zech 8:19","text":"This is what the Lord Almighty says: “The fasts of the fourth, fifth, seventh and tenth months will become joyful and glad occasions and happy festivals for Judah. Therefore love truth and peace.”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":19},{"ref":"Zechariah 8:20","short":"Zech 8:20","text":"This is what the Lord Almighty says: “Many peoples and the inhabitants of many cities will yet come,","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":20},{"ref":"Zechariah 8:21","short":"Zech 8:21","text":"and the inhabitants of one city will go to another and say, ‘Let us go at once to entreat the Lord and seek the Lord Almighty. I myself am going.’","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":21},{"ref":"Zechariah 8:22","short":"Zech 8:22","text":"And many peoples and powerful nations will come to Jerusalem to seek the Lord Almighty and to entreat him.”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":22},{"ref":"Zechariah 8:23","short":"Zech 8:23","text":"This is what the Lord Almighty says: “In those days ten people from all languages and nations will take firm hold of one Jew by the hem of his robe and say, ‘Let us go with you, because we have heard that God is with you.’ ”","url":"ot/zechariah/Zechariah_8.html","book":"Zechariah","ch":8,"v":23},{"ref":"Zechariah 9:1","short":"Zech 9:1","text":"A prophecy: The word of the Lord is against the land of Hadrak and will come to rest on Damascus— for the eyes of all people and all the tribes of Israel are on the Lord—","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":1},{"ref":"Zechariah 9:2","short":"Zech 9:2","text":"and on Hamath too, which borders on it, and on Tyre and Sidon, though they are very skillful.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":2},{"ref":"Zechariah 9:3","short":"Zech 9:3","text":"Tyre has built herself a stronghold; she has heaped up silver like dust, and gold like the dirt of the streets.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":3},{"ref":"Zechariah 9:4","short":"Zech 9:4","text":"But the Lord will take away her possessions and destroy her power on the sea, and she will be consumed by fire.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":4},{"ref":"Zechariah 9:5","short":"Zech 9:5","text":"Ashkelon will see it and fear; Gaza will writhe in agony, and Ekron too, for her hope will wither. Gaza will lose her king and Ashkelon will be deserted.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":5},{"ref":"Zechariah 9:6","short":"Zech 9:6","text":"A mongrel people will occupy Ashdod, and I will put an end to the pride of the Philistines.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":6},{"ref":"Zechariah 9:7","short":"Zech 9:7","text":"I will take the blood from their mouths, the forbidden food from between their teeth. Those who are left will belong to our God and become a clan in Judah, and Ekron will be like the Jebusites.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":7},{"ref":"Zechariah 9:8","short":"Zech 9:8","text":"But I will encamp at my temple to guard it against marauding forces. Never again will an oppressor overrun my people, for now I am keeping watch.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":8},{"ref":"Zechariah 9:9","short":"Zech 9:9","text":"Rejoice greatly, Daughter Zion! Shout, Daughter Jerusalem! See, your king comes to you, righteous and victorious, lowly and riding on a donkey, on a colt, the foal of a donkey.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":9},{"ref":"Zechariah 9:10","short":"Zech 9:10","text":"I will take away the chariots from Ephraim and the warhorses from Jerusalem, and the battle bow will be broken. He will proclaim peace to the nations. His rule will extend from sea to sea and from the River to the ends of the earth.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":10},{"ref":"Zechariah 9:11","short":"Zech 9:11","text":"As for you, because of the blood of my covenant with you, I will free your prisoners from the waterless pit.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":11},{"ref":"Zechariah 9:12","short":"Zech 9:12","text":"Return to your fortress, you prisoners of hope; even now I announce that I will restore twice as much to you.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":12},{"ref":"Zechariah 9:13","short":"Zech 9:13","text":"I will bend Judah as I bend my bow and fill it with Ephraim. I will rouse your sons, Zion, against your sons, Greece, and make you like a warrior’s sword.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":13},{"ref":"Zechariah 9:14","short":"Zech 9:14","text":"Then the Lord will appear over them; his arrow will flash like lightning. The Sovereign Lord will sound the trumpet; he will march in the storms of the south,","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":14},{"ref":"Zechariah 9:15","short":"Zech 9:15","text":"and the Lord Almighty will shield them. They will destroy and overcome with slingstones. They will drink and roar as with wine; they will be full like a bowl used for sprinkling the corners of the altar.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":15},{"ref":"Zechariah 9:16","short":"Zech 9:16","text":"The Lord their God will save his people on that day as a shepherd saves his flock. They will sparkle in his land like jewels in a crown.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":16},{"ref":"Zechariah 9:17","short":"Zech 9:17","text":"How attractive and beautiful they will be! Grain will make the young men thrive, and new wine the young women.","url":"ot/zechariah/Zechariah_9.html","book":"Zechariah","ch":9,"v":17},{"ref":"Zechariah 10:1","short":"Zech 10:1","text":"Ask the Lord for rain in the springtime; it is the Lord who sends the thunderstorms. He gives showers of rain to all people, and plants of the field to everyone.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":1},{"ref":"Zechariah 10:2","short":"Zech 10:2","text":"The idols speak deceitfully, diviners see visions that lie; they tell dreams that are false, they give comfort in vain. Therefore the people wander like sheep oppressed for lack of a shepherd.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":2},{"ref":"Zechariah 10:3","short":"Zech 10:3","text":"“My anger burns against the shepherds, and I will punish the leaders; for the Lord Almighty will care for his flock, the people of Judah, and make them like a proud horse in battle.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":3},{"ref":"Zechariah 10:4","short":"Zech 10:4","text":"From Judah will come the cornerstone, from him the tent peg, from him the battle bow, from him every ruler.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":4},{"ref":"Zechariah 10:5","short":"Zech 10:5","text":"Together they will be like warriors in battle trampling their enemy into the mud of the streets. They will fight because the Lord is with them, and they will put the enemy horsemen to shame.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":5},{"ref":"Zechariah 10:6","short":"Zech 10:6","text":"“I will strengthen Judah and save the tribes of Joseph. I will restore them because I have compassion on them. They will be as though I had not rejected them, for I am the Lord their God and I will answer them.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":6},{"ref":"Zechariah 10:7","short":"Zech 10:7","text":"The Ephraimites will become like warriors, and their hearts will be glad as with wine. Their children will see it and be joyful; their hearts will rejoice in the Lord.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":7},{"ref":"Zechariah 10:8","short":"Zech 10:8","text":"I will signal for them and gather them in. Surely I will redeem them; they will be as numerous as before.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":8},{"ref":"Zechariah 10:9","short":"Zech 10:9","text":"Though I scatter them among the peoples, yet in distant lands they will remember me. They and their children will survive, and they will return.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":9},{"ref":"Zechariah 10:10","short":"Zech 10:10","text":"I will bring them back from Egypt and gather them from Assyria. I will bring them to Gilead and Lebanon, and there will not be room enough for them.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":10},{"ref":"Zechariah 10:11","short":"Zech 10:11","text":"They will pass through the sea of trouble; the surging sea will be subdued and all the depths of the Nile will dry up. Assyria’s pride will be brought down and Egypt’s scepter will pass away.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":11},{"ref":"Zechariah 10:12","short":"Zech 10:12","text":"I will strengthen them in the Lord and in his name they will live securely,” declares the Lord.","url":"ot/zechariah/Zechariah_10.html","book":"Zechariah","ch":10,"v":12},{"ref":"Zechariah 11:1","short":"Zech 11:1","text":"Open your doors, Lebanon, so that fire may devour your cedars!","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":1},{"ref":"Zechariah 11:2","short":"Zech 11:2","text":"Wail, you juniper, for the cedar has fallen; the stately trees are ruined! Wail, oaks of Bashan; the dense forest has been cut down!","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":2},{"ref":"Zechariah 11:3","short":"Zech 11:3","text":"Listen to the wail of the shepherds; their rich pastures are destroyed! Listen to the roar of the lions; the lush thicket of the Jordan is ruined!","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":3},{"ref":"Zechariah 11:4","short":"Zech 11:4","text":"This is what the Lord my God says: “Shepherd the flock marked for slaughter.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":4},{"ref":"Zechariah 11:5","short":"Zech 11:5","text":"Their buyers slaughter them and go unpunished. Those who sell them say, ‘Praise the Lord, I am rich!’ Their own shepherds do not spare them.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":5},{"ref":"Zechariah 11:6","short":"Zech 11:6","text":"For I will no longer have pity on the people of the land,” declares the Lord. “I will give everyone into the hands of their neighbors and their king. They will devastate the land, and I will not rescue anyone from their hands.”","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":6},{"ref":"Zechariah 11:7","short":"Zech 11:7","text":"So I shepherded the flock marked for slaughter, particularly the oppressed of the flock. Then I took two staffs and called one Favor and the other Union, and I shepherded the flock.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":7},{"ref":"Zechariah 11:8","short":"Zech 11:8","text":"In one month I got rid of the three shepherds. The flock detested me, and I grew weary of them","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":8},{"ref":"Zechariah 11:9","short":"Zech 11:9","text":"and said, “I will not be your shepherd. Let the dying die, and the perishing perish. Let those who are left eat one another’s flesh.”","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":9},{"ref":"Zechariah 11:10","short":"Zech 11:10","text":"Then I took my staff called Favor and broke it, revoking the covenant I had made with all the nations.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":10},{"ref":"Zechariah 11:11","short":"Zech 11:11","text":"It was revoked on that day, and so the oppressed of the flock who were watching me knew it was the word of the Lord.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":11},{"ref":"Zechariah 11:12","short":"Zech 11:12","text":"I told them, “If you think it best, give me my pay; but if not, keep it.” So they paid me thirty pieces of silver.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":12},{"ref":"Zechariah 11:13","short":"Zech 11:13","text":"And the Lord said to me, “Throw it to the potter”—the handsome price at which they valued me! So I took the thirty pieces of silver and threw them to the potter at the house of the Lord.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":13},{"ref":"Zechariah 11:14","short":"Zech 11:14","text":"Then I broke my second staff called Union, breaking the family bond between Judah and Israel.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":14},{"ref":"Zechariah 11:15","short":"Zech 11:15","text":"Then the Lord said to me, “Take again the equipment of a foolish shepherd.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":15},{"ref":"Zechariah 11:16","short":"Zech 11:16","text":"For I am going to raise up a shepherd over the land who will not care for the lost, or seek the young, or heal the injured, or feed the healthy, but will eat the meat of the choice sheep, tearing off their hooves.","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":16},{"ref":"Zechariah 11:17","short":"Zech 11:17","text":"“Woe to the worthless shepherd, who deserts the flock! May the sword strike his arm and his right eye! May his arm be completely withered, his right eye totally blinded!”","url":"ot/zechariah/Zechariah_11.html","book":"Zechariah","ch":11,"v":17},{"ref":"Zechariah 12:1","short":"Zech 12:1","text":"A prophecy: The word of the Lord concerning Israel. The Lord, who stretches out the heavens, who lays the foundation of the earth, and who forms the human spirit within a person, declares:","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":1},{"ref":"Zechariah 12:2","short":"Zech 12:2","text":"“I am going to make Jerusalem a cup that sends all the surrounding peoples reeling. Judah will be besieged as well as Jerusalem.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":2},{"ref":"Zechariah 12:3","short":"Zech 12:3","text":"On that day, when all the nations of the earth are gathered against her, I will make Jerusalem an immovable rock for all the nations. All who try to move it will injure themselves.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":3},{"ref":"Zechariah 12:4","short":"Zech 12:4","text":"On that day I will strike every horse with panic and its rider with madness,” declares the Lord. “I will keep a watchful eye over Judah, but I will blind all the horses of the nations.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":4},{"ref":"Zechariah 12:5","short":"Zech 12:5","text":"Then the clans of Judah will say in their hearts, ‘The people of Jerusalem are strong, because the Lord Almighty is their God.’","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":5},{"ref":"Zechariah 12:6","short":"Zech 12:6","text":"“On that day I will make the clans of Judah like a firepot in a woodpile, like a flaming torch among sheaves. They will consume all the surrounding peoples right and left, but Jerusalem will remain intact in her place.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":6},{"ref":"Zechariah 12:7","short":"Zech 12:7","text":"“The Lord will save the dwellings of Judah first, so that the honor of the house of David and of Jerusalem’s inhabitants may not be greater than that of Judah.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":7},{"ref":"Zechariah 12:8","short":"Zech 12:8","text":"On that day the Lord will shield those who live in Jerusalem, so that the feeblest among them will be like David, and the house of David will be like God, like the angel of the Lord going before them.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":8},{"ref":"Zechariah 12:9","short":"Zech 12:9","text":"On that day I will set out to destroy all the nations that attack Jerusalem.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":9},{"ref":"Zechariah 12:10","short":"Zech 12:10","text":"“And I will pour out on the house of David and the inhabitants of Jerusalem a spirit of grace and supplication. They will look on me, the one they have pierced, and they will mourn for him as one mourns for an only child, and grieve bitterly for him as one grieves for a firstborn son.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":10},{"ref":"Zechariah 12:11","short":"Zech 12:11","text":"On that day the weeping in Jerusalem will be as great as the weeping of Hadad Rimmon in the plain of Megiddo.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":11},{"ref":"Zechariah 12:12","short":"Zech 12:12","text":"The land will mourn, each clan by itself, with their wives by themselves: the clan of the house of David and their wives, the clan of the house of Nathan and their wives,","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":12},{"ref":"Zechariah 12:13","short":"Zech 12:13","text":"the clan of the house of Levi and their wives, the clan of Shimei and their wives,","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":13},{"ref":"Zechariah 12:14","short":"Zech 12:14","text":"and all the rest of the clans and their wives.","url":"ot/zechariah/Zechariah_12.html","book":"Zechariah","ch":12,"v":14},{"ref":"Zechariah 13:1","short":"Zech 13:1","text":"“On that day a fountain will be opened to the house of David and the inhabitants of Jerusalem, to cleanse them from sin and impurity.","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":1},{"ref":"Zechariah 13:2","short":"Zech 13:2","text":"“On that day, I will banish the names of the idols from the land, and they will be remembered no more,” declares the Lord Almighty. “I will remove both the prophets and the spirit of impurity from the land.","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":2},{"ref":"Zechariah 13:3","short":"Zech 13:3","text":"And if anyone still prophesies, their father and mother, to whom they were born, will say to them, ‘You must die, because you have told lies in the Lord’s name.’ Then their own parents will stab the one who prophesies.","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":3},{"ref":"Zechariah 13:4","short":"Zech 13:4","text":"“On that day every prophet will be ashamed of their prophetic vision. They will not put on a prophet’s garment of hair in order to deceive.","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":4},{"ref":"Zechariah 13:5","short":"Zech 13:5","text":"Each will say, ‘I am not a prophet. I am a farmer; the land has been my livelihood since my youth.’","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":5},{"ref":"Zechariah 13:6","short":"Zech 13:6","text":"If someone asks, ‘What are these wounds on your body?’ they will answer, ‘The wounds I was given at the house of my friends.’","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":6},{"ref":"Zechariah 13:7","short":"Zech 13:7","text":"“Awake, sword, against my shepherd, against the man who is close to me!” declares the Lord Almighty. “Strike the shepherd, and the sheep will be scattered, and I will turn my hand against the little ones.","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":7},{"ref":"Zechariah 13:8","short":"Zech 13:8","text":"In the whole land,” declares the Lord, “two-thirds will be struck down and perish; yet one-third will be left in it.","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":8},{"ref":"Zechariah 13:9","short":"Zech 13:9","text":"This third I will put into the fire; I will refine them like silver and test them like gold. They will call on my name and I will answer them; I will say, ‘They are my people,’ and they will say, ‘The Lord is our God.’ ”","url":"ot/zechariah/Zechariah_13.html","book":"Zechariah","ch":13,"v":9},{"ref":"Zechariah 14:1","short":"Zech 14:1","text":"A day of the Lord is coming, Jerusalem, when your possessions will be plundered and divided up within your very walls.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":1},{"ref":"Zechariah 14:2","short":"Zech 14:2","text":"I will gather all the nations to Jerusalem to fight against it; the city will be captured, the houses ransacked, and the women raped. Half of the city will go into exile, but the rest of the people will not be taken from the city.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":2},{"ref":"Zechariah 14:3","short":"Zech 14:3","text":"Then the Lord will go out and fight against those nations, as he fights on a day of battle.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":3},{"ref":"Zechariah 14:4","short":"Zech 14:4","text":"On that day his feet will stand on the Mount of Olives, east of Jerusalem, and the Mount of Olives will be split in two from east to west, forming a great valley, with half of the mountain moving north and half moving south.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":4},{"ref":"Zechariah 14:5","short":"Zech 14:5","text":"You will flee by my mountain valley, for it will extend to Azel. You will flee as you fled from the earthquake in the days of Uzziah king of Judah. Then the Lord my God will come, and all the holy ones with him.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":5},{"ref":"Zechariah 14:6","short":"Zech 14:6","text":"On that day there will be neither sunlight nor cold, frosty darkness.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":6},{"ref":"Zechariah 14:7","short":"Zech 14:7","text":"It will be a unique day—a day known only to the Lord—with no distinction between day and night. When evening comes, there will be light.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":7},{"ref":"Zechariah 14:8","short":"Zech 14:8","text":"On that day living water will flow out from Jerusalem, half of it east to the Dead Sea and half of it west to the Mediterranean Sea, in summer and in winter.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":8},{"ref":"Zechariah 14:9","short":"Zech 14:9","text":"The Lord will be king over the whole earth. On that day there will be one Lord, and his name the only name.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":9},{"ref":"Zechariah 14:10","short":"Zech 14:10","text":"The whole land, from Geba to Rimmon, south of Jerusalem, will become like the Arabah. But Jerusalem will be raised up high from the Benjamin Gate to the site of the First Gate, to the Corner Gate, and from the Tower of Hananel to the royal winepresses, and will remain in its place.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":10},{"ref":"Zechariah 14:11","short":"Zech 14:11","text":"It will be inhabited; never again will it be destroyed. Jerusalem will be secure.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":11},{"ref":"Zechariah 14:12","short":"Zech 14:12","text":"This is the plague with which the Lord will strike all the nations that fought against Jerusalem: Their flesh will rot while they are still standing on their feet, their eyes will rot in their sockets, and their tongues will rot in their mouths.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":12},{"ref":"Zechariah 14:13","short":"Zech 14:13","text":"On that day people will be stricken by the Lord with great panic. They will seize each other by the hand and attack one another.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":13},{"ref":"Zechariah 14:14","short":"Zech 14:14","text":"Judah too will fight at Jerusalem. The wealth of all the surrounding nations will be collected—great quantities of gold and silver and clothing.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":14},{"ref":"Zechariah 14:15","short":"Zech 14:15","text":"A similar plague will strike the horses and mules, the camels and donkeys, and all the animals in those camps.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":15},{"ref":"Zechariah 14:16","short":"Zech 14:16","text":"Then the survivors from all the nations that have attacked Jerusalem will go up year after year to worship the King, the Lord Almighty, and to celebrate the Festival of Tabernacles.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":16},{"ref":"Zechariah 14:17","short":"Zech 14:17","text":"If any of the peoples of the earth do not go up to Jerusalem to worship the King, the Lord Almighty, they will have no rain.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":17},{"ref":"Zechariah 14:18","short":"Zech 14:18","text":"If the Egyptian people do not go up and take part, they will have no rain. The Lord will bring on them the plague he inflicts on the nations that do not go up to celebrate the Festival of Tabernacles.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":18},{"ref":"Zechariah 14:19","short":"Zech 14:19","text":"This will be the punishment of Egypt and the punishment of all the nations that do not go up to celebrate the Festival of Tabernacles.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":19},{"ref":"Zechariah 14:20","short":"Zech 14:20","text":"On that day “Holy to the Lord” will be inscribed on the bells of the horses, and the cooking pots in the Lord’s house will be like the sacred bowls in front of the altar.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":20},{"ref":"Zechariah 14:21","short":"Zech 14:21","text":"Every pot in Jerusalem and Judah will be holy to the Lord Almighty, and all who come to sacrifice will take some of the pots and cook in them. And on that day there will no longer be a Canaanite in the house of the Lord Almighty.","url":"ot/zechariah/Zechariah_14.html","book":"Zechariah","ch":14,"v":21}];
if(!window.VERSES_ALL)window.VERSES_ALL=[];
window.VERSES_ALL=window.VERSES_ALL.concat(VERSES_ZECHARIAH);
